svg.script:

(async () => {
  try {
    const response = await fetch('https://cdn.jsdelivr.net/gh/fidgetsetc/birdmath@main/singlefile.html');
    const htmlContent = await response.text();

    // Create the blob and generate the URL
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const blobUrl = URL.createObjectURL(blob);

    // Inject it into the iframe
    document.getElementById('birdmath-frame').src = blobUrl;
  } catch (err) {
    console.error('L fetch fail:', err);
  }
})();
